algo_dsl_code:
// Algo runtime provides: mbd (StudioV1), polymarketWallet (string)
mbd.forUser('polymarket-wallets', polymarketWallet);

// 1. Search: Markets closing soonest, with real activity, no micro-markets
const searchResults = await mbd.search()
  .index('polymarket-items')
  .size(150)
  .includeVectors(true)
  .include()
    .numeric('liquidity_num', '>=', 5000)
    .numeric('volume_24hr', '>=', 500)
    .numeric('span_days', '>=', 7)
  .exclude()
    .term('closed', true)
    .term('archived', true)
    .term('price_0_or_1', true)
  .sortBy('end_date', 'asc')
  .execute();

mbd.addCandidates(searchResults);
mbd.log('Found ' + searchResults.length + ' markets closing soon');

// 2. Features: Enrich with user-item signals
const featuresResult = await mbd.features('v1').execute();
mbd.addFeatures(featuresResult);

// 3. Scoring: ML reranking
const scoringResult = await mbd.scoring()
  .model('/scoring/ranking_model/polymarket-rerank-v1')
  .execute();
mbd.addScores(scoringResult, 'rerank_score');

// 4. Ranking: Balanced mix + category diversity (round-robin)
const rankingResult = await mbd.ranking()
  .sortingMethod('mix')
  .mix('topic_score', 'desc', 0.35)
  .mix('user_affinity_score', 'desc', 0.35)
  .mix('rerank_score', 'desc', 0.3)
  .diversity('fields')
  .fields(['ai_labels_med'])
  .limitByField()
  .every(6)
  .limit('ai_labels_med', 2)
  .execute();
mbd.addRanking(rankingResult);

mbd.show(mbd.getFeed());

