curl -X POST https://api.mbd.xyz/v3/studio/search/filter_and_sort \
  -H "Content-Type: application/json" \
  -H "Authorization: Bearer mbd-YOUR_API_KEY" \
  -d '{
    "index": "polymarket-items",
    "size": 150,
    "sort_by": { "field": "end_date", "order": "asc" },
    "include": [
      { "filter": "numeric", "field": "liquidity_num", "operator": ">=", "value": 5000 },
      { "filter": "numeric", "field": "volume_24hr", "operator": ">=", "value": 500 },
      { "filter": "numeric", "field": "span_days", "operator": ">=", "value": 7 }
    ],
    "exclude": [
      { "filter": "term", "field": "closed", "value": true },
      { "filter": "term", "field": "archived", "value": true },
      { "filter": "term", "field": "price_0_or_1", "value": true }
    ],
    "select_fields": ["question", "liquidity_num", "volume_24hr", "end_date", "last_trade_price", "spread", "tags"]
  }'
